void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("TortugaMayor_1");			link.l1 = StringFromKey("TortugaMayor_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("TortugaMayor_3");			link.l1 = StringFromKey("TortugaMayor_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("TortugaMayor_5");			link.l1 = StringFromKey("TortugaMayor_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("TortugaMayor_7");			link.l1 = StringFromKey("TortugaMayor_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("TortugaMayor_9");			link.l1 = "...";			link.l1.go = "exit";		break;		/* -------------------------------------------------------------------- */		case "5":			dialog.text = StringFromKey("TortugaMayor_10");			link.l1 = StringFromKey("TortugaMayor_11");			link.l1.go = "6";		break;		case "6":			dialog.text = StringFromKey("TortugaMayor_12");			link.l1 = StringFromKey("TortugaMayor_13");			link.l1.go = "7";		break;		case "7":			dialog.text = StringFromKey("TortugaMayor_14");			link.l1 = StringFromKey("TortugaMayor_15");			link.l1.go = "exit";		break;		case "":			dialog.text = "";			link.l1 = "";			link.l1.go = "";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}